			if methodName == "ToBoolean" then
				return "((" .. args .. ") and true or false)"
			end
		end
		if obj == "Task" then
			if methodName == "Run" then
				return "task.spawn(" .. args .. ")"
			end
			if methodName == "Delay" then
				return "task.wait(" .. args .. " / 1000)"
			end
			if methodName == "WhenAll" then
				self._needsRuntime = true
				return "__rt.whenAll(" .. args .. ")"
			end
			if methodName == "WhenAny" then
				self._needsRuntime = true
				return "__rt.whenAny(" .. args .. ")"
			end
		end
		if obj == "Task.Factory" and methodName == "StartNew" then
			return "task.spawn(" .. args .. ")"
		end
		if obj == "Parallel" and methodName == "ForEach" then
			if #inv.Arguments == 2 then
				local collection = SimpleEmitter.EmitExpression(self, inv.Arguments[0 + 1])
				local action = SimpleEmitter.EmitExpression(self, inv.Arguments[1 + 1])
				return "(function() for _, __v in " .. collection .. " do task.spawn(function() (" .. action .. ")(__v) end) end end)()"
			end
		end
		if obj == "string" or obj == "String" then
			if methodName == "IsNullOrWhiteSpace" then
				return "(" .. args .. " == nil or string.match(" .. args .. ", \"^%s*$\") ~= nil)"
			end
			if methodName == "Join" then
				if #inv.Arguments == 2 then
					local sep = SimpleEmitter.EmitExpression(self, inv.Arguments[0 + 1])
					local arr = SimpleEmitter.EmitExpression(self, inv.Arguments[1 + 1])
					return "table.concat(" .. arr .. ", " .. sep .. ")"
				end
			end
			if methodName == "Concat" then
				local concatResult = ""
				local i = 0
				while i < #inv.Arguments do
					if i > 0 then
						concatResult = concatResult .. " .. "
					end
					concatResult = concatResult .. "tostring(" .. SimpleEmitter.EmitExpression(self, inv.Arguments[i + 1]) .. ")"
					i += 1
				end
				return concatResult
			end
			if methodName == "Format" then
				self._needsRuntime = true
				return "__rt.stringFormat(" .. args .. ")"
			end
		end
		if obj == "Enumerable" then
			self._needsRuntime = true
			if methodName == "Range" then
				return "__rt.range(" .. args .. ")"
			end
			if methodName == "Repeat" then
				return "__rt.repeat_(" .. args .. ")"
			end
			if methodName == "Empty" then
				return "{}"
			end
		end
		if obj == "base" and self._baseClassName ~= nil then
			if #args > 0 then
				return self._baseClassName .. "." .. methodName .. "(self, " .. args .. ")"
			end
			return self._baseClassName .. "." .. methodName .. "(self)"
		end
		if SimpleEmitter.IsInstanceCallTarget(self, ma.Expression, obj) then
			return obj .. ":" .. methodName .. "(" .. args .. ")"
		end
		return obj .. "." .. methodName .. "(" .. args .. ")"
	end
	if inv.Expression.Kind == 8616 then
		local preCheckId = inv.Expression
		if preCheckId.Identifier.Text == "nameof" and #inv.Arguments == 1 then
			local nameofArg = SimpleEmitter.EmitExpression(self, inv.Arguments[0 + 1])
			local dotPos = #nameofArg - 1
			while dotPos >= 0 and string.byte(nameofArg, dotPos + 1) ~= 46 do
				dotPos = dotPos - 1
			end
			if dotPos >= 0 then
				return "\"" .. string.sub(nameofArg, dotPos .. 1 + 1) .. "\""
			end
			return "\"" .. nameofArg .. "\""
		end
	end
	if inv.Expression.Kind == 8616 then
		local calleeId = inv.Expression
		local methodName = calleeId.Identifier.Text
		if not self._isStaticContext and #self._currentClassName > 0 and SimpleEmitter.IsInstanceMethod(self, methodName) then
			if #args > 0 then
				return self._currentClassName .. "." .. methodName .. "(self, " .. args .. ")"
			end
			return self._currentClassName .. "." .. methodName .. "(self)"
		end
		if #self._currentClassName > 0 and SimpleEmitter.IsStaticMethod(self, methodName) then
			return self._currentClassName .. "." .. methodName .. "(" .. args .. ")"
		end
	end
	local callee = SimpleEmitter.EmitExpression(self, inv.Expression)
	return callee .. "(" .. args .. ")"
end

function SimpleEmitter.EmitObjectCreation(self: SimpleEmitter, expr: ExpressionSyntax): string
	local obj = expr
	local args = ""
	local i = 0
	while i < #obj.Arguments do
		if i > 0 then
			args = args .. ", "
		end
		args = args .. SimpleEmitter.EmitExpression(self, obj.Arguments[i + 1])
		i += 1
	end
	local typeName = obj.TypeName
	if typeName == "StringBuilder" then
		return "\"\""
	end
	if #typeName > 5 and string.sub(typeName, 0 + 1, 0 + 5) == "List<" then
		return "{}"
	end
	if #typeName > 11 and string.sub(typeName, 0 + 1, 0 + 11) == "Dictionary<" then
		return "{}"
	end
	if #typeName > 8 and string.sub(typeName, 0 + 1, 0 + 8) == "HashSet<" then
		return "{}"
	end
	if #typeName > 6 and string.sub(typeName, 0 + 1, 0 + 6) == "Queue<" then
		return "{}"
	end
	if #typeName > 6 and string.sub(typeName, 0 + 1, 0 + 6) == "Stack<" then
		return "{}"
	end
	if typeName == "Random" then
		if #obj.Arguments > 0 then
			return "Random.new(" .. args .. ")"
		end
		return "Random.new()"
	end
	if typeName == "Stopwatch" then
		self._needsRuntime = true
		return "__rt.Stopwatch.StartNew()"
	end
	if typeName == "CancellationTokenSource" then
		self._needsRuntime = true
		return "__rt.CancellationToken.new()"
	end
	if typeName == "Exception" or typeName == "InvalidOperationException" or typeName == "ArgumentException" or typeName == "ArgumentNullException" or typeName == "NotImplementedException" or typeName == "NotSupportedException" or typeName == "IndexOutOfRangeException" or typeName == "OverflowException" then
		if #obj.Arguments > 0 then
			return SimpleEmitter.EmitExpression(self, obj.Arguments[0 + 1])
		end
		return "\"" .. typeName .. "\""
	end
	if #obj.Initializers > 0 then
		local iife = "(function() local __obj = " .. typeName .. ".new(" .. args .. "); "
		local i = 0
		while i < #obj.Initializers do
			local fieldName = SimpleEmitter.EmitExpression(self, obj.Initializers[i + 1].Left)
			local fieldVal = SimpleEmitter.EmitExpression(self, obj.Initializers[i + 1].Right)
			iife = iife .. "__obj." .. fieldName .. " = " .. fieldVal .. "; "
			i += 1
		end
		iife = iife .. "return __obj end)()"
		return iife
	end
	if #typeName > 2 and string.sub(typeName, #typeName - 2 + 1) == "[]" then
		if #args == 0 then
			return "{}"
		end
		local elems = ""
		local i = 0
		while i < #obj.Arguments do
			if i > 0 then
				elems = elems .. ", "
			end
			elems = elems .. SimpleEmitter.EmitExpression(self, obj.Arguments[i + 1])
			i += 1
		end
		return "{ " .. elems .. " }"
	end
	return typeName .. ".new(" .. args .. ")"
end

function SimpleEmitter.EmitArrayCreation(self: SimpleEmitter, expr: ExpressionSyntax): string
	local arr = expr
	if arr.SizeExpression ~= nil then
		local size = SimpleEmitter.EmitExpression(self, arr.SizeExpression)
		return "table.create(" .. size .. ")"
	end
	return "{}"
end

function SimpleEmitter.GetVariableType(self: SimpleEmitter, name: string): string
	local i = 0
	while i < self._paramCount do
		if self._paramNames[i + 1] == name then
			return self._paramTypes[i + 1]
		end
		i += 1
	end
	local i = 0
	while i < self._localCount do
		if self._localNames[i + 1] == name then
			return self._localTypes[i + 1]
		end
		i += 1
	end
	return nil
end

function SimpleEmitter.IsStringType(self: SimpleEmitter, typeName: string): boolean
	if typeName == nil then
		return false
	end
	if typeName == "string" then
		return true
	end
	if typeName == "String" then
		return true
	end
	return false
end

function SimpleEmitter.TransformInterpolationExpr(self: SimpleEmitter, csExpr: string): string
	local trimmed = csExpr
	while #trimmed > 0 and string.byte(trimmed, 0 + 1) == 32 do
		trimmed = string.sub(trimmed, 1 + 1)
	end
	while #trimmed > 0 and string.byte(trimmed, #trimmed - 1 + 1) == 32 do
		trimmed = string.sub(trimmed, 0 + 1, 0 + #trimmed - 1)
	end
	if #trimmed == 0 then
		return csExpr
	end
	if #trimmed > 7 and string.sub(trimmed, #trimmed - 7 + 1) == ".Length" then
		local obj = string.sub(trimmed, 0 + 1, 0 + #trimmed - 7)
		return "#" .. obj
	end
	if #trimmed > 6 and string.sub(trimmed, #trimmed - 6 + 1) == ".Count" then
		local obj = string.sub(trimmed, 0 + 1, 0 + #trimmed - 6)
		return "#" .. obj
	end
	if #trimmed > 11 and string.sub(trimmed, #trimmed - 11 + 1) == ".ToString()" then
		local obj = string.sub(trimmed, 0 + 1, 0 + #trimmed - 11)
		return "tostring(" .. obj .. ")"
	end
	if #trimmed > 10 and string.sub(trimmed, #trimmed - 10 + 1) == ".ToLower()" then
		local obj = string.sub(trimmed, 0 + 1, 0 + #trimmed - 10)
		return "string.lower(" .. obj .. ")"
	end
	if #trimmed > 10 and string.sub(trimmed, #trimmed - 10 + 1) == ".ToUpper()" then
		local obj = string.sub(trimmed, 0 + 1, 0 + #trimmed - 10)
		return "string.upper(" .. obj .. ")"
	end
	if #trimmed > 7 and string.sub(trimmed, #trimmed - 7 + 1) == ".Trim()" then
		local obj = string.sub(trimmed, 0 + 1, 0 + #trimmed - 7)
		return "string.match(" .. obj .. ", \"^%s*(.-)%s*$\")"
	end
	return trimmed
end

function SimpleEmitter.GetIdentifierName(self: SimpleEmitter, expr: ExpressionSyntax): string
	if expr.Kind == 8616 then
		local id = expr
		return id.Identifier.Text
	end
	return nil
end

function SimpleEmitter.GetFieldType(self: SimpleEmitter, fieldName: string): string
	local i = 0
	while i < self._fieldCount do
		if self._fieldNames[i + 1] == fieldName then
			return self._fieldTypes[i + 1]
		end
		i += 1
	end
	return nil
end

function SimpleEmitter.IsStringExpression(self: SimpleEmitter, expr: ExpressionSyntax): boolean
	if expr.Kind == 8616 then
		local id = expr
		local name = id.Identifier.Text
		local varType = SimpleEmitter.GetVariableType(self, name)
		if varType ~= nil then
			return SimpleEmitter.IsStringType(self, varType)
		end
		if not self._isStaticContext then
			local fieldType = SimpleEmitter.GetFieldType(self, name)
			if fieldType ~= nil then
				return SimpleEmitter.IsStringType(self, fieldType)
			end
		end
	end
	if expr.Kind == 8689 then
		local ma = expr
		if ma.Expression.Kind == 8616 then
			local leftId = ma.Expression
			local leftName = leftId.Identifier.Text
			if leftName == "this" or leftName == "self" then
				local fieldType = SimpleEmitter.GetFieldType(self, ma.Name.Text)
				if fieldType ~= nil then
					return SimpleEmitter.IsStringType(self, fieldType)
				end
			end
		end
	end
	return false
end

function SimpleEmitter.EmitElementAccess(self: SimpleEmitter, expr: ExpressionSyntax): string
	local ea = expr
	local obj = SimpleEmitter.EmitExpression(self, ea.Expression)
	local index = SimpleEmitter.EmitExpression(self, ea.Index)
	local isStringIndex = SimpleEmitter.IsStringExpression(self, ea.Expression)
	if isStringIndex then
		if ea.Index.Kind == 8750 then
			local lit = ea.Index
			local numText = lit.Token.Text
			local numVal = 0
			local isSimple = true
			local i = 0
			while i < #numText do
				local c = string.byte(numText, i + 1)
				if c >= 48 and c <= 57 then
					numVal = numVal * 10 + (c - 48)
				else
					isSimple = false
				end
				i += 1
			end
			if isSimple then
				return "string.byte(" .. obj .. ", " .. SimpleEmitter.IntToString(self, numVal .. 1) .. ")"
			end
		end
		return "string.byte(" .. obj .. ", " .. index .. " + 1)"
	end
	if ea.Index.Kind == 8750 then
		local lit = ea.Index
		local numText = lit.Token.Text
		local numVal = 0
		local isSimple = true
		local i = 0
		while i < #numText do
			local c = string.byte(numText, i + 1)
			if c >= 48 and c <= 57 then
				numVal = numVal * 10 + (c - 48)
			else
				isSimple = false
			end
			i += 1
		end
		if isSimple then
			return obj .. "[" .. SimpleEmitter.IntToString(self, numVal .. 1) .. "]"
		end
	end
	return obj .. "[" .. index .. " + 1]"
end

function SimpleEmitter.EmitLambda(self: SimpleEmitter, expr: ExpressionSyntax): string
	local lam = expr
	local parms = ""
	local i = 0
	while i < #lam.ParameterNames do
		if i > 0 then
			parms = parms .. ", "
		end
		parms = parms .. lam.ParameterNames[i + 1]
		i += 1
	end
	if lam.ExpressionBody ~= nil then
		return "function(" .. parms .. ") return " .. SimpleEmitter.EmitExpression(self, lam.ExpressionBody) .. " end"
	end
	if lam.BlockBody ~= nil then
		local savedOutput = self._output
		local savedIndent = self._indent
		self._output = ""
		self._indent = 0
		SimpleEmitter.EmitBlockBody(self, lam.BlockBody)
		local body = self._output
		self._output = savedOutput
		self._indent = savedIndent
		if #body > 0 and string.byte(body, #body - 1 + 1) == 10 then
			body = string.sub(body, 0 + 1, 0 + #body - 1)
		end
		return "function(" .. parms .. ")\n" .. body .. "\nend"
	end
	return "function(" .. parms .. ") end"
end

function SimpleEmitter.EmitSwitchExpression(self: SimpleEmitter, expr: ExpressionSyntax): string
	local sw = expr
	local govExpr = SimpleEmitter.EmitExpression(self, sw.GoverningExpression)
	local result = ""
	local i = 0
	while i < #sw.Arms do
		local arm = sw.Arms[i + 1]
		local armExpr = SimpleEmitter.EmitExpression(self, arm.Expression)
		if arm.Pattern == nil then
			if #result == 0 then
				result = armExpr
			else
				result = result .. " else " .. armExpr
			end
		else
			local patternExpr = SimpleEmitter.EmitExpression(self, arm.Pattern)
			if #result == 0 then
				result = "if " .. govExpr .. " == " .. patternExpr .. " then " .. armExpr
			else
				result = result .. " elseif " .. govExpr .. " == " .. patternExpr .. " then " .. armExpr
			end
		end
		i += 1
	end
	return result
end

function SimpleEmitter.IntToString(self: SimpleEmitter, value: number): string
	if value == 0 then
		return "0"
	end
	local negative = false
	if value < 0 then
		negative = true
		value = -value
	end
	local result = ""
	local n = value
	while n > 0 do
		local digit = n % 10
		local c = (48 + digit)
		result = c .. result
		n = n / 10
	end
	if negative then
		result = "-" .. result
	end
	return result
end

return { SimpleEmitter = SimpleEmitter }
